import (
	"math"
	"strconv"
)

// isPrime checks if a number is prime.
func isPrime(k int64) bool {
	if k <= 1 {
		return false
	}
	if k <= 3 {
		return true
	}
	if k%2 == 0 || k%3 == 0 {
		return false
	}
	var i int64 = 5
	for i*i <= k {
		if k%i == 0 || k%(i+2) == 0 {
			return false
		}
		i += 6
	}
	return true
}

// reverseNumber reverses the digits of a number.
func reverseNumber(n int64) int64 {
	s := strconv.FormatInt(n, 10)
	runes := []rune(s)
	for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
		runes[i], runes[j] = runes[j], runes[i]
	}
	reversedStr := string(runes)
	r, _ := strconv.ParseInt(reversedStr, 10, 64)
	return r
}

// solve calculates the sum of all prime numbers between min(n, r) and max(n, r) inclusive,
// where r is the reverse of n.
func solve(n int64) int64 {
	r := reverseNumber(n)

	start := n
	end := r
	if start > end {
		start, end = end, start
	}

	var sum int64 = 0
	for i := start; i <= end; i++ {
		if isPrime(i) {
			sum += i
		}
	}

	return sum
}
